def _parse(text: str) -> np.ndarray:
    rows = [list(map(int, r.split())) for r in text.strip().splitlines()]
    return np.array(rows, dtype=np.int32)
PUZZLES = [(_parse(p), _parse(s)) for (p, s) in _PUZZLES]

def random_puzzle(rng: np.random.Generator) -> tuple[np.ndarray, np.ndarray]:
    i = int(rng.integers(0, len(PUZZLES)))
    (p, s) = PUZZLES[i]
    return (p.copy(), s.copy())

def n_puzzles() -> int:
    return len(PUZZLES)
